import type * as DMMF from '@prisma/dmmf'

/** Maps a DMMF scalar/enum/object type name to its TypeScript equivalent. */
export function dmmfTypeToTs(field: DMMF.Field): string {
  let tsType: string

  if (field.kind === 'enum') {
    tsType = field.type
  } else if (field.kind === 'object') {
    tsType = field.type
  } else {
    tsType = scalarToTs(field.type)
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (!field.isRequired) {
    tsType = `${tsType} | null`
  }

  return tsType
}

function scalarToTs(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Bytes':
      return 'Uint8Array'
    case 'Json':
      return 'unknown'
    default:
      return 'unknown'
  }
}

/**
 * Renders a TypeScript string literal union type for a DMMF enum.
 *
 * Example output:
 * ```ts
 * export type Role = 'USER' | 'ADMIN'
 * ```
 */
export function renderEnumType(dmmfEnum: DMMF.DatamodelEnum): string {
  const values = dmmfEnum.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${dmmfEnum.name} = ${values}`
}

/**
 * Renders a TypeScript interface for all scalar and enum fields of a model.
 * Relation fields (`kind === 'object'`) are intentionally excluded because
 * they are not transferable as flat REST JSON payloads.
 */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const optional = !f.isRequired ? '?' : ''
      const type = dmmfTypeToTs({ ...f, isRequired: true })
      const nullSuffix = !f.isRequired ? ' | null' : ''
      return `  ${f.name}${optional}: ${type}${nullSuffix}`
    })

  return [`export interface ${model.name} {`, ...fields, '}'].join('\n')
}

/**
 * Renders the WhereUniqueInput type for a model, including all `@id` and
 * `@unique` scalar fields as optional keys.
 */
export function renderWhereUniqueInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' && (f.isId || f.isUnique))
    .map((f) => `  ${f.name}?: ${scalarToTs(f.type)}`)

  return [`export interface ${model.name}WhereUniqueInput {`, ...fields, '}'].join('\n')
}

/**
 * Renders the CreateInput type: required scalar/enum fields that are not
 * auto-generated (no `@id @default(...)` or `@updatedAt`), with optional
 * fields carrying a `?` modifier.
 */
export function renderCreateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !(f.isId && f.hasDefaultValue) && !f.isUpdatedAt)
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      const type = dmmfTypeToTs({ ...f, isRequired: true })
      const nullSuffix = !f.isRequired ? ' | null' : ''
      return `  ${f.name}${optional}: ${type}${nullSuffix}`
    })

  return [`export interface ${model.name}CreateInput {`, ...fields, '}'].join('\n')
}

/**
 * Renders the UpdateInput type: same fields as CreateInput but all optional.
 */
export function renderUpdateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !(f.isId && f.hasDefaultValue) && !f.isUpdatedAt)
    .map((f) => {
      const type = dmmfTypeToTs({ ...f, isRequired: true })
      const nullSuffix = !f.isRequired ? ' | null' : ''
      return `  ${f.name}?: ${type}${nullSuffix}`
    })

  return [`export interface ${model.name}UpdateInput {`, ...fields, '}'].join('\n')
}

/** Returns the first `@id` field name for a model, or `'id'` as a fallback. */
export function getIdFieldName(model: DMMF.Model): string {
  return model.fields.find((f) => f.isId)?.name ?? 'id'
}

/** Returns a lowercase-plural REST path segment for a model name, e.g. `User` → `users`. */
export function toRestPath(modelName: string): string {
  const lower = modelName.charAt(0).toLowerCase() + modelName.slice(1)
  // Minimal English pluralisation: covers the common cases without a library.
  if (lower.endsWith('s') || lower.endsWith('x') || lower.endsWith('z') || lower.endsWith('ch') || lower.endsWith('sh')) {
    return `${lower}es`
  }
  if (lower.endsWith('y') && !/[aeiou]y$/.test(lower)) {
    return `${lower.slice(0, -1)}ies`
  }
  return `${lower}s`
}

/**
 * Renders the individual `ModelRestClient` class for one model, including
 * all five CRUD methods and the private `#request` helper.
 */
export function renderModelClient(model: DMMF.Model): string {
  const name = model.name
  const path = toRestPath(name)
  const idField = getIdFieldName(model)

  return `
class ${name}RestClient {
  readonly #config: RestClientConfig

  constructor(config: RestClientConfig) {
    this.#config = config
  }

  async findMany(params?: {
    where?: Partial<${name}>
    skip?: number
    take?: number
  }): Promise<${name}[]> {
    const query = buildQuery(params)
    return this.#request<${name}[]>('GET', \`/${path}\${query}\`)
  }

  async findUnique(params: { where: ${name}WhereUniqueInput }): Promise<${name} | null> {
    const id = params.where.${idField}
    return this.#request<${name} | null>('GET', \`/${path}/\${id}\`)
  }

  async create(params: { data: ${name}CreateInput }): Promise<${name}> {
    return this.#request<${name}>('POST', '/${path}', params.data)
  }

  async update(params: { where: ${name}WhereUniqueInput; data: ${name}UpdateInput }): Promise<${name}> {
    const id = params.where.${idField}
    return this.#request<${name}>('PATCH', \`/${path}/\${id}\`, params.data)
  }

  async delete(params: { where: ${name}WhereUniqueInput }): Promise<${name}> {
    const id = params.where.${idField}
    return this.#request<${name}>('DELETE', \`/${path}/\${id}\`)
  }

  async #request<T>(method: string, path: string, body?: unknown): Promise<T> {
    const url = \`\${this.#config.baseUrl}\${path}\`
    const response = await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json', ...this.#config.headers },
      body: body !== undefined ? JSON.stringify(body) : undefined,
    })
    if (!response.ok) {
      throw new Error(\`REST API error: \${response.status} \${response.statusText}\`)
    }
    return response.json() as Promise<T>
  }
}`
}

/**
 * Renders the top-level `PrismaRestClient` class that exposes a typed
 * accessor property for each model.
 */
export function renderRootClient(models: readonly DMMF.Model[]): string {
  const properties = models.map((m) => {
    const propName = m.name.charAt(0).toLowerCase() + m.name.slice(1)
    return `  readonly ${propName}: ${m.name}RestClient`
  })

  const assignments = models.map((m) => {
    const propName = m.name.charAt(0).toLowerCase() + m.name.slice(1)
    return `    this.${propName} = new ${m.name}RestClient(config)`
  })

  return [
    'export class PrismaRestClient {',
    ...properties,
    '',
    '  constructor(config: RestClientConfig) {',
    ...assignments,
    '  }',
    '}',
  ].join('\n')
}

