import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorConfig, GeneratorOptions } from '@prisma/generator'

import {
  renderCreateInput,
  renderEnumType,
  renderModelClient,
  renderModelInterface,
  renderRootClient,
  renderUpdateInput,
  renderWhereUniqueInput,
} from './template'

/**
 * Resolves the output directory from the generator config.
 * Handles both plain string paths and `env("VAR_NAME")` references.
 */
function resolveOutputDir(config: GeneratorConfig): string {
  if (!config.output) {
    throw new Error(
      'An output path is required for the `prisma-generator-rest-client` generator.\n\n' +
        'Add an output field to your schema:\n\n' +
        '  generator restClient {\n' +
        '    provider = "prisma-generator-rest-client"\n' +
        '    output   = "./generated/rest-client"\n' +
        '  }\n',
    )
  }

  if (config.output.fromEnvVar) {
    const value = process.env[config.output.fromEnvVar]
    if (!value) {
      throw new Error(
        `Environment variable "${config.output.fromEnvVar}" referenced by the rest-client generator output is not set.`,
      )
    }
    return value
  }

  if (!config.output.value) {
    throw new Error('The rest-client generator output path is empty.')
  }

  return config.output.value
}

/** Produces the full text of the generated `rest-client.ts` file. */
function buildFileContent(dmmf: DMMF.Document): string {
  const { models, enums } = dmmf.datamodel
  const sections: string[] = []

  sections.push(
    '// Auto-generated by @prisma/generator-rest-client — do not edit directly.',
    '// Re-run `prisma generate` to update this file.',
    '',
  )

  // ---- Config & shared helpers ----
  sections.push(
    'export interface RestClientConfig {',
    '  /** Base URL of the REST API, without a trailing slash (e.g. `https://api.example.com`). */',
    '  baseUrl: string',
    '  /** Optional HTTP headers sent with every request (e.g. `Authorization`). */',
    '  headers?: Record<string, string>',
    '}',
    '',
    '/** Serialises findMany query params to a URL query string. */',
    'function buildQuery(params?: { where?: unknown; skip?: number; take?: number }): string {',
    '  if (!params) return \'\'',
    '  const entries: string[] = []',
    '  if (params.where !== undefined) entries.push(`where=${encodeURIComponent(JSON.stringify(params.where))}`)',
    '  if (params.skip !== undefined) entries.push(`skip=${params.skip}`)',
    '  if (params.take !== undefined) entries.push(`take=${params.take}`)',
    '  return entries.length ? `?${entries.join(\'&\')}` : \'\'',
    '}',
    '',
  )

  // ---- Enums ----
  if (enums.length > 0) {
    sections.push('// ---------------------------------------------------------------------------')
    sections.push('// Enums')
    sections.push('// ---------------------------------------------------------------------------')
    sections.push('')
    for (const dmmfEnum of enums) {
      sections.push(renderEnumType(dmmfEnum))
      sections.push('')
    }
  }

  // ---- Model interfaces and input types ----
  sections.push('// ---------------------------------------------------------------------------')
  sections.push('// Models')
  sections.push('// ---------------------------------------------------------------------------')
  sections.push('')
  for (const model of models) {
    sections.push(renderModelInterface(model))
    sections.push('')
    sections.push(renderWhereUniqueInput(model))
    sections.push('')
    sections.push(renderCreateInput(model))
    sections.push('')
    sections.push(renderUpdateInput(model))
    sections.push('')
  }

  // ---- Root client ----
  sections.push('// ---------------------------------------------------------------------------')
  sections.push('// Client')
  sections.push('// ---------------------------------------------------------------------------')
  sections.push('')
  sections.push(renderRootClient(models))
  sections.push('')

  // ---- Per-model client classes ----
  for (const model of models) {
    sections.push(renderModelClient(model))
    sections.push('')
  }

  return sections.join('\n')
}

/**
 * Entry point called by the generator protocol.
 * Reads the DMMF from `options`, generates the REST client source file, and
 * writes it to the configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputDir(options.generator)
  await fs.mkdir(outputDir, { recursive: true })

  const content = buildFileContent(options.dmmf)
  const outputFile = path.join(outputDir, 'rest-client.ts')
