 * accessor property for each model.
 */
export function renderRootClient(models: readonly DMMF.Model[]): string {
  const properties = models.map((m) => {
    const propName = m.name.charAt(0).toLowerCase() + m.name.slice(1)
    return `  readonly ${propName}: ${m.name}RestClient`
  })

  const assignments = models.map((m) => {
    const propName = m.name.charAt(0).toLowerCase() + m.name.slice(1)
    return `    this.${propName} = new ${m.name}RestClient(config)`
  })

  return [
    'export class PrismaRestClient {',
    ...properties,
    '',
    '  constructor(config: RestClientConfig) {',
    ...assignments,
    '  }',
    '}',
  ].join('\n')
}
